import React from 'react';
import TotalVisitsCard from '../components/Dashboard/TotalVisitsCard';
import ActiveVisitorsCard from '../components/Dashboard/ActiveVisitorsCard';
import AlertsSection from '../components/Dashboard/AlertsSection';
import { LayoutDashboard, Users, Bell, ShieldAlert } from 'lucide-react';

const Dashboard = () => {
  return (
    <div className="flex h-screen bg-dark-bg overflow-hidden font-inter">
      {/* Sidebar - Minimalist glass design */}
      <aside className="w-64 glass border-r border-white/10 hidden md:flex flex-col p-6 space-y-8">
        <div className="flex items-center space-x-3 px-2">
          <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center shadow-lg shadow-primary/20">
            <ShieldAlert className="text-white w-5 h-5" />
          </div>
          <span className="text-xl font-bold tracking-tight text-white">SACHA <span className="text-primary">ADMIN</span></span>
        </div>

        <nav className="flex-1 space-y-2">
          <NavItem icon={<LayoutDashboard size={20} />} label="Analytics" active />
          <NavItem icon={<Users size={20} />} label="Visitors" />
          <NavItem icon={<Bell size={20} />} label="Alerts" badge="3" />
        </nav>

        <div className="p-4 rounded-xl bg-gradient-to-br from-primary/10 to-transparent border border-white/5">
          <p className="text-xs text-white/50 mb-1">System Status</p>
          <div className="flex items-center space-x-2">
            <div className="w-2 h-2 rounded-full bg-success animate-pulse" />
            <span className="text-sm font-medium text-success">Operational</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8">
        <header className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-extrabold text-white tracking-tight">Advanced Analytics</h1>
            <p className="text-white/50 mt-1">Real-time overview of visitor activity and system health.</p>
          </div>
          <div className="flex items-center space-x-4">
             {/* Profile/Quick Actions */}
             <div className="w-10 h-10 rounded-full glass border border-white/20 flex items-center justify-center cursor-pointer hover:border-primary/50 transition-colors">
               <span className="text-xs font-bold text-primary">AD</span>
             </div>
          </div>
        </header>

        {/* Dashboard Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
          <div className="lg:col-span-8 space-y-6">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <TotalVisitsCard />
                <ActiveVisitorsCard />
             </div>
             {/* Future expansion: Large Chart */}
             <div className="glass rounded-2xl p-6 h-64 flex items-center justify-center border border-white/5">
                <p className="text-white/20 uppercase tracking-widest text-sm font-bold">Occupancy Heatmap Coming Soon</p>
             </div>
          </div>
          <div className="lg:col-span-4">
            <AlertsSection />
          </div>
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ icon, label, active, badge }) => (
  <div className={`flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all duration-300 ${active ? 'bg-primary/20 text-primary border border-primary/20 shadow-lg shadow-primary/5' : 'text-white/50 hover:bg-white/5 hover:text-white'}`}>
    <div className="flex items-center space-x-3">
      {icon}
      <span className="font-semibold">{label}</span>
    </div>
    {badge && <span className="bg-danger text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full">{badge}</span>}
  </div>
);

export default Dashboard;
